INSERT INTO innovations (title, authors, institution, year, field, abstract, citations, arxiv_id, impact_score) VALUES
('Why Constitutional AI changes everything about alignment',            ARRAY['alice_chen'],          'Anthropic Blog',   2024, 'AI Safety',          'Most alignment approaches treat safety as a constraint. Constitutional AI makes it intrinsic to training — the model learns to critique and revise its own outputs.', 1420, NULL,         91.4),
('Zero-copy HTTP parsing in Rust: a deep dive',                        ARRAY['rustacean'],           'Blog',             2024, 'Systems',            'How we shaved 40% off Cloudflare request latency with a custom SIMD HTTP parser. Includes benchmarks against hyper, actix, and nginx.', 2140, NULL,         88.7),
('Mechanistic interpretability: a practitioner''s guide',             ARRAY['mlresearcher'],        'arXiv',            2024, 'ML Research',        'How to use activation patching and causal tracing to understand what your model does. Covers superposition, circuits, and feature visualization.', 1540, '2401.11234', 93.2),
('Migrating 500 microservices to Kubernetes without downtime',         ARRAY['devopsguru'],          'Stripe Blog',      2023, 'Platform Eng',       'The 18-month journey, the near-disasters, and the monitoring setup that saved us. Full runbook included.', 1870, NULL,         87.1),
('Delta Lake in production: what the docs don''t tell you',           ARRAY['datawrangler'],        'dev.to',           2024, 'Data Engineering',   'The gotchas, the tuning knobs, and the schema evolution patterns we learned building petabyte-scale lakehouses.', 980,  NULL,         82.4),
('Terraform at scale: managing 10,000 resources without going insane', ARRAY['gopher_dev'],          'HashiCorp Blog',   2023, 'DevOps',             'Module patterns, state management strategies, and the drift detection setup that actually works in enterprise.', 1340, NULL,         84.9),
('eBPF security in production: lessons from two years at Cloudflare',  ARRAY['securitymind'],        'Blog',             2024, 'Security',           'What we learned running eBPF-based intrusion detection across 300 PoPs. Pitfalls, false positives, and kernel version hell.', 920,  NULL,         81.3),
('The future of frontend is at the edge',                              ARRAY['frontendwitch'],       'Vercel Blog',      2024, 'Frontend',           'Why server components, edge rendering, and streaming make SPAs look like 2018. React 19 changes everything.', 2240, NULL,         89.5),
('Quantum advantage for ML: myth or near future?',                     ARRAY['quantumleap'],         'arXiv',            2024, 'Quantum Computing',  'A sober look at where quantum speedups for machine learning are plausible in the 2025-2030 timeframe. No hype.', 780,  '2402.09871', 79.6),
('Fine-tuning Llama 3 on a consumer GPU: a practical guide',           ARRAY['ossenthusiast'],       'Hugging Face Blog',2024, 'ML / LLMs',          'QLoRA, PEFT, and the exact config that gets you 90% of full fine-tune quality on an RTX 4090 in under 6 hours.', 3240, NULL,         94.7),
('Multi-region Kubernetes that doesn''t bankrupt you',                 ARRAY['k8swhisperer'],        'Google Blog',      2023, 'SRE',                'Architecture patterns for global HA Kubernetes without the AWS bill shock. Covers Thanos, global load balancing, and failover.', 1120, NULL,         83.8),
('Rewriting Firefox CSS in Rust: 3 years in the trenches',            ARRAY['rustformers'],         'Mozilla Blog',     2024, 'Systems / Rust',     'What we learned shipping 2 million lines of Rust to 200 million Firefox users. Memory safety, performance, and team dynamics.', 2670, NULL,         92.1),
('Vitess query optimizer deep dive',                                   ARRAY['dboptimizer'],         'PlanetScale Blog', 2024, 'Databases',          'How Vitess plans and executes distributed MySQL queries. Join routing, scatter-gather, and when the planner makes mistakes.', 890,  NULL,         80.5),
('The risks of moving fast with AI deployment',                        ARRAY['aiethicist'],          'Anthropic Blog',   2024, 'AI Ethics',          'What responsible AI deployment looks like when the stakes are societal. Monitoring, rollback, and the cases where you should not ship.', 1120, NULL,         85.2),
('Durable execution: the programming model the cloud needs',           ARRAY['grpcmaster'],          'Temporal Blog',    2023, 'Distributed Systems','Why your distributed systems should be modeled as workflows, not state machines. How durable execution handles failures you haven''t thought of.', 1430, NULL,         86.7),
('RAG pipelines in production: the parts nobody talks about',          ARRAY['vectorvault'],         'Weaviate Blog',    2024, 'AI / RAG',           'Chunking strategies, reranking, hybrid search, and why naive RAG will disappoint you in production. Real benchmarks.', 1870, NULL,         88.3),
('Mixtral MoE: training a sparse mixture-of-experts at scale',        ARRAY['llmwhisperer'],        'arXiv',            2024, 'ML / LLMs',          'The engineering behind training Mixtral. Expert routing, load balancing, and why sparse MoE beats dense at inference time.', 2340, '2401.04088', 92.8),
('Serverless Postgres branching workflows for teams',                  ARRAY['cloudnative'],         'Neon Blog',        2024, 'Databases',          'How to use database branching in CI/CD. Every PR gets its own Postgres, schema migrations are safe, and prod stays clean.', 1240, NULL,         84.1),
('Secrets management at scale with Vault and Kubernetes',              ARRAY['cryptoeng'],           'HashiCorp Blog',   2023, 'Security / DevOps',  'How to run Vault as a secrets backbone for 50+ Kubernetes clusters. PKI, mTLS, and dynamic credentials without the chaos.', 980,  NULL,         81.9),
('Multi-region Postgres on Fly.io: a field guide',                     ARRAY['edgerunner'],          'Fly.io Blog',      2024, 'Infrastructure',     'Anycast routing, regional read replicas, and write forwarding patterns for globally distributed Postgres on Fly.io.', 860,  NULL,         80.4);
INSERT INTO trends (name, category, momentum_score, year_emerged, description, related_tags, adoption_stage) VALUES
('Rust',                     'Systems',         94, 2016, 'Memory-safe systems language replacing C/C++ in production. Dominant in WASM, embedded, and performance-critical services.', ARRAY['systems','memory-safety','WASM','performance'], 'mainstream'),
('eBPF',                     'Systems',         87, 2020, 'Programmable Linux kernel observability. Powers the next generation of network security, tracing, and performance tooling.', ARRAY['linux','networking','observability','security'], 'growing'),
('Kubernetes',               'Platform',        91, 2017, 'Container orchestration standard. Every serious production workload runs on k8s or a managed variant.', ARRAY['containers','devops','SRE','cloud'], 'mainstream'),
('Large Language Models',    'AI/ML',           98, 2020, 'Foundation models trained on vast corpora enabling few-shot learning across tasks. Reshaping every software category.', ARRAY['LLM','transformers','GPT','generative-AI'], 'mainstream'),
('RAG Pipelines',            'AI/ML',           92, 2022, 'Grounding LLM outputs with retrieval from external documents. The dominant pattern for production AI that needs fresh data.', ARRAY['RAG','vector-db','LLM','semantic-search'], 'growing'),
('WebAssembly',              'Runtime',         79, 2018, 'Binary instruction format enabling near-native performance in browsers and server-side sandboxed environments.', ARRAY['WASM','performance','portable','edge'], 'growing'),
('Vector Databases',         'Databases',       88, 2021, 'Specialized stores for high-dimensional embeddings. Essential infrastructure for semantic search and RAG.', ARRAY['embeddings','semantic-search','RAG','AI'], 'growing'),
('Durable Execution',        'Architecture',    74, 2022, 'Programming model ensuring long-running workflows survive infrastructure failures through automatic checkpointing.', ARRAY['temporal','reliability','distributed','workflow'], 'emerging'),
('QLora / PEFT',             'AI/ML',           85, 2023, 'Parameter-efficient fine-tuning techniques making LLM customization accessible on consumer hardware.', ARRAY['fine-tuning','LLM','efficiency','open-source'], 'growing'),
('Serverless Postgres',      'Databases',       82, 2022, 'Postgres with auto-scaling, scale-to-zero billing, and branching. Neon and others making DB infra invisible.', ARRAY['postgres','serverless','branching','cloud'], 'growing'),
('Edge Computing',           'Infrastructure',  85, 2019, 'Running compute at the network edge close to users. Cloudflare Workers, Fly.io, and Vercel Edge Functions lead.', ARRAY['CDN','serverless','latency','Cloudflare'], 'mainstream'),
('Mechanistic Interpretability','AI/ML',        78, 2022, 'Understanding what neural networks actually compute. Circuits, superposition, and feature visualization research.', ARRAY['interpretability','AI-safety','transformers','research'], 'emerging'),
('Mixture of Experts',       'AI/ML',           83, 2023, 'Sparse model architecture routing tokens to specialized sub-networks. Mixtral proved MoE beats dense at inference cost.', ARRAY['MoE','LLM','efficiency','scaling'], 'growing'),
('Terraform / OpenTofu',     'DevOps',          88, 2014, 'Infrastructure-as-code standard. OpenTofu fork gaining momentum after HashiCorp license change.', ARRAY['IaC','DevOps','cloud','infrastructure'], 'mainstream'),
('AI Safety & Alignment',    'AI/ML',           80, 2021, 'Technical research ensuring AI systems do what humans intend. Constitutional AI, RLHF, and interpretability converge here.', ARRAY['AI-safety','alignment','RLHF','anthropic'], 'growing'),
('Multi-region Databases',   'Databases',       76, 2021, 'Globally distributed databases with strong consistency guarantees. CockroachDB, Spanner, and PlanetScale leading.', ARRAY['distributed','databases','global','consistency'], 'growing'),
('Go',                       'Languages',       86, 2012, 'Google''s systems language. Dominant for cloud-native tooling, Kubernetes ecosystem, and developer tools.', ARRAY['golang','cloud-native','kubernetes','devops'], 'mainstream'),
('Zero Trust Security',      'Security',        84, 2020, 'Never trust, always verify. mTLS everywhere, identity-based access, and continuous auth replacing perimeter security.', ARRAY['security','mTLS','identity','zero-trust'], 'growing'),
('TypeScript',               'Languages',       92, 2018, 'Typed JavaScript now the default for any serious frontend or Node.js project. React, Next.js, and Deno run on it.', ARRAY['typescript','javascript','frontend','node'], 'mainstream'),
('Observability (OpenTelemetry)','Platform',    83, 2021, 'Unified traces, metrics, and logs via OpenTelemetry. Replacing bespoke APM with vendor-neutral instrumentation.', ARRAY['observability','tracing','OpenTelemetry','SRE'], 'growing');
